-- Table: faction_chat
DROP TABLE IF EXISTS `faction_chat`;
CREATE TABLE `faction_chat` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `job` enum('police','hospital','sannews','trader','grove','ballas','vagos','aztecaz','riffa') NOT NULL COMMENT 'Job faction',
  `username` varchar(50) NOT NULL COMMENT 'Username pengirim',
  `message` text NOT NULL COMMENT 'Isi pesan',
  `message_type` enum('text','photo','video') DEFAULT 'text' COMMENT 'Tipe pesan',
  `media_url` varchar(500) DEFAULT NULL COMMENT 'URL file (foto/video)',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp() COMMENT 'Waktu kirim pesan',
  PRIMARY KEY (`id`),
  KEY `idx_job` (`job`),
  KEY `idx_username` (`username`),
  KEY `idx_created` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: faction_members
DROP TABLE IF EXISTS `faction_members`;
CREATE TABLE `faction_members` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL COMMENT 'Username player',
  `faction` enum('godside','badside') NOT NULL COMMENT 'Godside atau Badside',
  `job` enum('police','hospital','sannews','trader','grove','ballas','vagos','aztecaz','riffa') NOT NULL COMMENT 'Job faction',
  `rank` enum('leader','co_leader','member') DEFAULT 'member' COMMENT 'Rank: Leader/Co-Leader/Member',
  `invited_date` timestamp NOT NULL DEFAULT current_timestamp() COMMENT 'Kapan di-invite ke faction',
  `is_online` tinyint(1) DEFAULT 0 COMMENT 'Status online/offline',
  `last_active` timestamp NULL DEFAULT NULL COMMENT 'Terakhir aktif',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  KEY `idx_faction` (`faction`),
  KEY `idx_job` (`job`),
  KEY `idx_rank` (`rank`),
  KEY `idx_username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


