-- Table: fraction_wh
DROP TABLE IF EXISTS `fraction_wh`;
CREATE TABLE `fraction_wh` (
  `id` int(11) NOT NULL,
  `weapon` int(11) NOT NULL,
  `ammo` int(11) NOT NULL,
  `money` int(11) NOT NULL,
  `drugs` int(11) NOT NULL,
  `state` int(11) NOT NULL,
  UNIQUE KEY `id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: game_slot
DROP TABLE IF EXISTS `game_slot`;
CREATE TABLE `game_slot` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `gName` varchar(50) NOT NULL,
  `gPhone` varchar(20) NOT NULL,
  `gCoin` bigint(20) DEFAULT 100,
  `gMode` enum('easy','normal','hard') DEFAULT 'normal',
  `gLid` varchar(30) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `gName` (`gName`),
  UNIQUE KEY `gPhone` (`gPhone`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: gangzone
DROP TABLE IF EXISTS `gangzone`;
CREATE TABLE `gangzone` (
  `ginfo1` float NOT NULL,
  `ginfo2` float NOT NULL,
  `ginfo3` float NOT NULL,
  `ginfo4` float NOT NULL,
  `fraction` int(11) NOT NULL,
  `id` int(11) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: garbages
DROP TABLE IF EXISTS `garbages`;
CREATE TABLE `garbages` (
  `id` int(11) NOT NULL,
  `garbageModel` int(11) DEFAULT 1236,
  `garbageX` float DEFAULT 0,
  `garbageY` float DEFAULT 0,
  `garbageZ` float DEFAULT 0,
  `garbageRx` float DEFAULT 0,
  `garbageRy` float DEFAULT 0,
  `garbageRz` float DEFAULT 0,
  `garbageInterior` int(11) DEFAULT 0,
  `garbageWorld` int(11) DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: garkot
DROP TABLE IF EXISTS `garkot`;
CREATE TABLE `garkot` (
  `id` int(11) NOT NULL,
  `posx` float DEFAULT 0,
  `posy` float DEFAULT 0,
  `posz` float DEFAULT 0,
  `posa` float DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: gates
DROP TABLE IF EXISTS `gates`;
CREATE TABLE `gates` (
  `ID` int(11) NOT NULL,
  `model` int(11) NOT NULL DEFAULT 0,
  `password` varchar(36) NOT NULL DEFAULT '',
  `admin` tinyint(4) NOT NULL DEFAULT 0,
  `vip` tinyint(4) NOT NULL DEFAULT 0,
  `faction` tinyint(4) NOT NULL DEFAULT 0,
  `family` int(11) NOT NULL DEFAULT -1,
  `speed` float NOT NULL DEFAULT 2,
  `cX` float NOT NULL,
  `cY` float NOT NULL,
  `cZ` float NOT NULL,
  `cRX` float NOT NULL,
  `cRY` float NOT NULL,
  `cRZ` float NOT NULL,
  `oX` float NOT NULL,
  `oY` float NOT NULL,
  `oZ` float NOT NULL,
  `oRX` float NOT NULL,
  `oRY` float NOT NULL,
  `oRZ` float NOT NULL,
  PRIMARY KEY (`ID`)
) ENGINE=MyISAM DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


-- Table: getcord
DROP TABLE IF EXISTS `getcord`;
CREATE TABLE `getcord` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `Name` varchar(24) DEFAULT NULL,
  `X` float DEFAULT NULL,
  `Y` float DEFAULT NULL,
  `Z` float DEFAULT NULL,
  `A` float DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: global_chat
DROP TABLE IF EXISTS `global_chat`;
CREATE TABLE `global_chat` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `message` text NOT NULL,
  `photo_url` varchar(255) DEFAULT NULL,
  `video_url` varchar(255) DEFAULT NULL,
  `reply_to` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: graffiti
DROP TABLE IF EXISTS `graffiti`;
CREATE TABLE `graffiti` (
  `id` int(11) NOT NULL,
  `owner_frac` int(11) NOT NULL,
  `color_owner` varchar(32) NOT NULL DEFAULT 'null',
  `block` int(11) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: grup_settings
DROP TABLE IF EXISTS `grup_settings`;
CREATE TABLE `grup_settings` (
  `jid` varchar(100) NOT NULL,
  `antilink` tinyint(1) NOT NULL DEFAULT 0,
  `welcome` tinyint(1) NOT NULL DEFAULT 0,
  `mute` tinyint(1) NOT NULL DEFAULT 0,
  `nsfw` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`jid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: guide_chat
DROP TABLE IF EXISTS `guide_chat`;
CREATE TABLE `guide_chat` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `guide_id` int(11) NOT NULL,
  `username` varchar(255) NOT NULL,
  `role` enum('leader','representative','member') NOT NULL,
  `message` text NOT NULL,
  `reply_to_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `guide_id` (`guide_id`),
  KEY `reply_to_id` (`reply_to_id`),
  CONSTRAINT `guide_chat_ibfk_1` FOREIGN KEY (`guide_id`) REFERENCES `guides` (`id`) ON DELETE CASCADE,
  CONSTRAINT `guide_chat_ibfk_2` FOREIGN KEY (`reply_to_id`) REFERENCES `guide_chat` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: guide_invites
DROP TABLE IF EXISTS `guide_invites`;
CREATE TABLE `guide_invites` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `guide_id` int(11) NOT NULL,
  `invited_username` varchar(255) NOT NULL,
  `inviter` varchar(255) NOT NULL,
  `status` enum('pending','accepted','rejected') DEFAULT 'pending',
  `expires_at` datetime NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `guide_id` (`guide_id`),
  CONSTRAINT `guide_invites_ibfk_1` FOREIGN KEY (`guide_id`) REFERENCES `guides` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: guide_members
DROP TABLE IF EXISTS `guide_members`;
CREATE TABLE `guide_members` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `guide_id` int(11) NOT NULL,
  `username` varchar(255) NOT NULL,
  `role` enum('leader','representative','member') NOT NULL,
  `joined_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_member` (`username`),
  KEY `guide_id` (`guide_id`),
  CONSTRAINT `guide_members_ibfk_1` FOREIGN KEY (`guide_id`) REFERENCES `guides` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: guides
DROP TABLE IF EXISTS `guides`;
CREATE TABLE `guides` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `leader` varchar(255) NOT NULL,
  `representative1` varchar(255) NOT NULL,
  `representative2` varchar(255) NOT NULL,
  `max_members` int(11) NOT NULL,
  `current_members` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: hotels
DROP TABLE IF EXISTS `hotels`;
CREATE TABLE `hotels` (
  `id` int(11) NOT NULL,
  `hOwned` int(11) NOT NULL,
  `hOwner` varchar(32) NOT NULL DEFAULT 'null',
  `hRentTime` int(11) NOT NULL,
  `hLock` int(11) NOT NULL,
  `hPrice` int(11) NOT NULL DEFAULT 50000
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: house
DROP TABLE IF EXISTS `house`;
CREATE TABLE `house` (
  `hID` int(11) NOT NULL,
  `hEntrancex` float NOT NULL,
  `hEntrancey` float NOT NULL,
  `hEntrancez` float NOT NULL,
  `hCarx` float NOT NULL,
  `hCary` float NOT NULL,
  `hCarz` float NOT NULL,
