-- Table: house_lodgers
DROP TABLE IF EXISTS `house_lodgers`;
CREATE TABLE `house_lodgers` (
  `h_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  UNIQUE KEY `user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: hunters
DROP TABLE IF EXISTS `hunters`;
CREATE TABLE `hunters` (
  `phone` varchar(20) NOT NULL,
  `name` varchar(50) NOT NULL,
  `role` varchar(30) NOT NULL,
  `level` int(11) NOT NULL DEFAULT 1,
  `money` bigint(20) NOT NULL DEFAULT 500,
  `hp` int(11) NOT NULL DEFAULT 1000,
  `hp_max` int(11) NOT NULL DEFAULT 1000,
  `weapon` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`weapon`)),
  `inventory` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`inventory`)),
  `potion_active` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`potion_active`)),
  `companions` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`companions`)),
  `pending_req` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`pending_req`)),
  `linked_assassin` varchar(20) DEFAULT NULL,
  `request_sent_to` varchar(20) DEFAULT NULL,
  `last_war` bigint(20) NOT NULL DEFAULT 0,
  `war_cd` bigint(20) NOT NULL DEFAULT 0,
  `total_kill` int(11) NOT NULL DEFAULT 0,
  `total_money` bigint(20) NOT NULL DEFAULT 0,
  `wins` int(11) NOT NULL DEFAULT 0,
  `losses` int(11) NOT NULL DEFAULT 0,
  `pvp_wins` int(11) NOT NULL DEFAULT 0,
  `pvp_losses` int(11) NOT NULL DEFAULT 0,
  `pvp_challenge` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`pvp_challenge`)),
  `last_dungeon` bigint(20) NOT NULL DEFAULT 0,
  `dungeon_wins` int(11) NOT NULL DEFAULT 0,
  `notif_chat` varchar(100) DEFAULT NULL,
  `health_req` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`health_req`)),
  `potion_req` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`potion_req`)),
  PRIMARY KEY (`phone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: inv_mancing
DROP TABLE IF EXISTS `inv_mancing`;
CREATE TABLE `inv_mancing` (
  `phone` varchar(20) NOT NULL,
  `ikan` varchar(50) NOT NULL,
  `jumlah` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`phone`,`ikan`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: inv_tambang
DROP TABLE IF EXISTS `inv_tambang`;
CREATE TABLE `inv_tambang` (
  `phone` varchar(20) NOT NULL,
  `mineral` varchar(50) NOT NULL,
  `jumlah` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`phone`,`mineral`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: inventory
DROP TABLE IF EXISTS `inventory`;
CREATE TABLE `inventory` (
  `invID` int(11) NOT NULL AUTO_INCREMENT,
  `ID` int(11) NOT NULL DEFAULT 0,
  `invItem` varchar(32) DEFAULT NULL,
  `invModel` varchar(32) NOT NULL DEFAULT '0',
  `invQuantity` varchar(32) NOT NULL DEFAULT '0',
  `invType` int(11) NOT NULL DEFAULT 0,
  `invTotal` varchar(32) NOT NULL DEFAULT '0',
  PRIMARY KEY (`invID`)
) ENGINE=InnoDB AUTO_INCREMENT=183 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: item_slot
DROP TABLE IF EXISTS `item_slot`;
CREATE TABLE `item_slot` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `gPhone` varchar(20) NOT NULL,
  `itemId` varchar(50) NOT NULL,
  `expireAt` bigint(20) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_item` (`gPhone`,`itemId`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: item_spawn_history
DROP TABLE IF EXISTS `item_spawn_history`;
CREATE TABLE `item_spawn_history` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `item_code` varchar(50) NOT NULL,
  `username` varchar(50) NOT NULL,
  `quantity` int(11) NOT NULL,
  `spawned_by` varchar(50) NOT NULL,
  `reason` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_item_code` (`item_code`),
  KEY `idx_username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: item_templates
DROP TABLE IF EXISTS `item_templates`;
CREATE TABLE `item_templates` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `item_code` varchar(50) NOT NULL,
  `item_name` varchar(100) NOT NULL,
  `item_category` enum('legal','illegal') NOT NULL,
  `item_type` varchar(50) DEFAULT NULL,
  `icon_url` varchar(255) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `max_limit` int(11) DEFAULT 999,
  `is_tradeable` tinyint(1) DEFAULT 1,
  `rarity` enum('common','uncommon','rare','epic','legendary') DEFAULT 'common',
  `base_price` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `item_code` (`item_code`)
) ENGINE=InnoDB AUTO_INCREMENT=8750 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: items
DROP TABLE IF EXISTS `items`;
CREATE TABLE `items` (
  `phone` varchar(20) NOT NULL,
  `item_key` varchar(50) NOT NULL,
  `expires_at` bigint(20) NOT NULL DEFAULT 0,
  PRIMARY KEY (`phone`,`item_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: kill_log
DROP TABLE IF EXISTS `kill_log`;
CREATE TABLE `kill_log` (
  `id` int(11) NOT NULL DEFAULT 0,
  `text` varchar(150) NOT NULL DEFAULT '',
  `date` datetime NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

-- Table: last_message
DROP TABLE IF EXISTS `last_message`;
CREATE TABLE `last_message` (
  `username` varchar(50) NOT NULL,
  `last_sent` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`username`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: login_sessions
DROP TABLE IF EXISTS `login_sessions`;
CREATE TABLE `login_sessions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(24) NOT NULL,
  `session_token` varchar(128) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_token` (`session_token`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: market_digital
DROP TABLE IF EXISTS `market_digital`;
CREATE TABLE `market_digital` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `photo_url` varchar(255) DEFAULT NULL,
  `username` varchar(50) NOT NULL,
  `asset_name` varchar(100) NOT NULL,
  `asset_type` enum('house','business','vehicle','motorcycle') NOT NULL,
  `description` text DEFAULT NULL,
  `price` int(11) NOT NULL,
  `location` varchar(255) DEFAULT NULL,
  `phone` varchar(20) NOT NULL,
  `samp_id` int(11) NOT NULL,
  `features` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`features`)),
  `status` enum('active','sold','reserved') DEFAULT 'active',
  `views` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_asset_type` (`asset_type`),
  KEY `idx_status` (`status`),
  KEY `idx_price` (`price`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: marketplace
DROP TABLE IF EXISTS `marketplace`;
CREATE TABLE `marketplace` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(255) NOT NULL,
  `image_url` text DEFAULT NULL,
  `product_name` varchar(255) NOT NULL,
  `price` int(11) NOT NULL,
  `type` enum('legal','illegal') NOT NULL,
  `phone` varchar(20) NOT NULL,
  `samp_number` varchar(50) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: money_log
DROP TABLE IF EXISTS `money_log`;
CREATE TABLE `money_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL DEFAULT 0,
  `amount` int(11) NOT NULL DEFAULT 0,
  `reason` varchar(128) NOT NULL DEFAULT '',
  `type` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=507 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: notifications
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL DEFAULT 0,
  `title` varchar(128) NOT NULL DEFAULT '',
  `message` text NOT NULL,
  `type` tinyint(1) NOT NULL DEFAULT 0,
  `is_read` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: online_log
DROP TABLE IF EXISTS `online_log`;
CREATE TABLE `online_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `day` varchar(16) NOT NULL,
  `play_time` int(11) NOT NULL,
  `afk_time` int(11) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1046 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: online_record
DROP TABLE IF EXISTS `online_record`;
CREATE TABLE `online_record` (
  `newid` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `players` int(11) NOT NULL,
  `time` int(11) NOT NULL,
  PRIMARY KEY (`newid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: others
DROP TABLE IF EXISTS `others`;
CREATE TABLE `others` (
  `numberbanks` int(11) NOT NULL,
  `election_status` int(11) NOT NULL,
  `bonus_exp` int(11) NOT NULL,
  `bonus_donate` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: otp_codes
DROP TABLE IF EXISTS `otp_codes`;
CREATE TABLE `otp_codes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `phone` varchar(20) NOT NULL,
  `code` varchar(6) NOT NULL,
  `expires_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: otp_sessions
DROP TABLE IF EXISTS `otp_sessions`;
CREATE TABLE `otp_sessions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(24) NOT NULL,
  `phone` varchar(20) NOT NULL,
  `otp_code` varchar(6) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `expires_at` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: private_chat
DROP TABLE IF EXISTS `private_chat`;
CREATE TABLE `private_chat` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `sender` varchar(50) NOT NULL,
  `receiver` varchar(50) NOT NULL,
  `message` text NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: private_contacts
DROP TABLE IF EXISTS `private_contacts`;
CREATE TABLE `private_contacts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `owner` varchar(255) NOT NULL,
  `contact_name` varchar(255) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_contact` (`owner`,`contact_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: promocodes
DROP TABLE IF EXISTS `promocodes`;
CREATE TABLE `promocodes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `amount` int(11) NOT NULL,
  `code` varchar(32) NOT NULL,
  `reward` int(11) NOT NULL,
  UNIQUE KEY `code` (`code`),
  UNIQUE KEY `id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

-- Table: race_checkpoints
DROP TABLE IF EXISTS `race_checkpoints`;
CREATE TABLE `race_checkpoints` (
  `id` int(11) NOT NULL,
  `track_id` int(11) NOT NULL,
  `cp_order` int(11) NOT NULL,
  `pos_x` float NOT NULL,
  `pos_y` float NOT NULL,
  `pos_z` float NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: race_tracks
DROP TABLE IF EXISTS `race_tracks`;
CREATE TABLE `race_tracks` (
  `id` int(11) NOT NULL,
  `name` varchar(64) NOT NULL,
  `owner` varchar(24) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: riba_slot
DROP TABLE IF EXISTS `riba_slot`;
CREATE TABLE `riba_slot` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `peminjamPhone` varchar(20) NOT NULL,
  `pemberiPhone` varchar(20) NOT NULL,
  `peminjamName` varchar(50) NOT NULL,
  `pemberiName` varchar(50) NOT NULL,
  `pokok` bigint(20) NOT NULL,
  `bunga` bigint(20) NOT NULL,
  `totalTagihan` bigint(20) NOT NULL,
  `jatuhTempo` bigint(20) NOT NULL,
  `status` enum('aktif','lunas','macet') DEFAULT 'aktif',
  `createdAt` bigint(20) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: roulet_prizes
DROP TABLE IF EXISTS `roulet_prizes`;
CREATE TABLE `roulet_prizes` (
  `user_id` int(11) NOT NULL,
  `item_id` int(11) NOT NULL,
  `amount` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: rpg_heroes
DROP TABLE IF EXISTS `rpg_heroes`;
CREATE TABLE `rpg_heroes` (
  `phone` varchar(20) NOT NULL,
  `name` varchar(50) NOT NULL,
  `job` varchar(30) NOT NULL,
  `level` int(11) NOT NULL DEFAULT 1,
  `exp` int(11) NOT NULL DEFAULT 0,
  `exp_next` int(11) NOT NULL DEFAULT 100,
  `hp` int(11) NOT NULL DEFAULT 100,
  `hp_max` int(11) NOT NULL DEFAULT 100,
  `atk` int(11) NOT NULL DEFAULT 10,
  `def` int(11) NOT NULL DEFAULT 5,
  `coin` bigint(20) NOT NULL DEFAULT 0,
  `stamina` int(11) NOT NULL DEFAULT 10,
  `stamina_max` int(11) NOT NULL DEFAULT 10,
  `stamina_last_regen` bigint(20) NOT NULL DEFAULT 0,
  `wins` int(11) NOT NULL DEFAULT 0,
  `losses` int(11) NOT NULL DEFAULT 0,
  `kills` int(11) NOT NULL DEFAULT 0,
  `inventory` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`inventory`)),
  `equip` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`equip`)),
  `last_hunt` bigint(20) NOT NULL DEFAULT 0,
  `last_dungeon` bigint(20) NOT NULL DEFAULT 0,
  `last_rest` bigint(20) NOT NULL DEFAULT 0,
  PRIMARY KEY (`phone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: saham_harga
DROP TABLE IF EXISTS `saham_harga`;
CREATE TABLE `saham_harga` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `kode` varchar(10) NOT NULL,
  `nama` varchar(50) NOT NULL,
  `emoji` varchar(10) NOT NULL,
  `harga` int(11) NOT NULL,
  `hargaAwal` int(11) NOT NULL,
  `event` varchar(20) DEFAULT 'normal',
  `updatedAt` bigint(20) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `kode` (`kode`)
) ENGINE=InnoDB AUTO_INCREMENT=256 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: saham_portofolio
DROP TABLE IF EXISTS `saham_portofolio`;
CREATE TABLE `saham_portofolio` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `gPhone` varchar(20) NOT NULL,
  `kode` varchar(10) NOT NULL,
  `jumlah` int(11) NOT NULL DEFAULT 0,
  `avgBeli` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_porto` (`gPhone`,`kode`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: shops
DROP TABLE IF EXISTS `shops`;
CREATE TABLE `shops` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `type` int(11) NOT NULL,
  `x` float NOT NULL,
  `y` float NOT NULL,
  `z` float NOT NULL,
  `vw` int(11) NOT NULL,
  `intt` int(11) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: stats_slot
DROP TABLE IF EXISTS `stats_slot`;
CREATE TABLE `stats_slot` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `gPhone` varchar(20) NOT NULL,
  `totalMain` int(11) DEFAULT 0,
  `totalMenang` int(11) DEFAULT 0,
  `totalKalah` int(11) DEFAULT 0,
  `totalWin` bigint(20) DEFAULT 0,
  `totalLose` bigint(20) DEFAULT 0,
  PRIMARY KEY (`id`),
  UNIQUE KEY `gPhone` (`gPhone`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: streak
DROP TABLE IF EXISTS `streak`;
CREATE TABLE `streak` (
  `phone` varchar(20) NOT NULL,
  `value` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`phone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: streak_slot
DROP TABLE IF EXISTS `streak_slot`;
CREATE TABLE `streak_slot` (
  `gPhone` varchar(20) NOT NULL,
  `streak` int(11) DEFAULT 0,
  `lastWin` bigint(20) DEFAULT 0,
  PRIMARY KEY (`gPhone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: supports
DROP TABLE IF EXISTS `supports`;
CREATE TABLE `supports` (
  `user_id` int(11) NOT NULL,
  `reports` int(11) NOT NULL,
  `reports_day` int(11) NOT NULL,
  `offer` varchar(32) NOT NULL,
  `invite_date` datetime NOT NULL DEFAULT current_timestamp(),
  UNIQUE KEY `user_id` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: taxi_bizz
DROP TABLE IF EXISTS `taxi_bizz`;
CREATE TABLE `taxi_bizz` (
  `b_id` int(11) NOT NULL,
  `c_id` int(11) NOT NULL,
  `model` int(11) NOT NULL,
  `fuel` float NOT NULL,
  `price` int(11) NOT NULL DEFAULT 500
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: transfer_history
DROP TABLE IF EXISTS `transfer_history`;
CREATE TABLE `transfer_history` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `sender` varchar(50) NOT NULL,
  `receiver` varchar(50) NOT NULL,
  `amount` int(11) NOT NULL,
  `transfer_type` enum('pCash','pBank') NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: trees
DROP TABLE IF EXISTS `trees`;
CREATE TABLE `trees` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `x` float NOT NULL DEFAULT 0,
  `y` float NOT NULL DEFAULT 0,
  `z` float NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: tweetlogs
DROP TABLE IF EXISTS `tweetlogs`;
CREATE TABLE `tweetlogs` (
  `Name` varchar(32) DEFAULT 'None',
  `Text` varchar(128) DEFAULT 'None',
  `Time` varchar(255) DEFAULT 'None'
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


-- Table: tweets
DROP TABLE IF EXISTS `tweets`;
CREATE TABLE `tweets` (
  `ID` int(11) DEFAULT 1,
  `TwitterFrom` varchar(64) NOT NULL DEFAULT '-',
  `TwitterDate` varchar(64) DEFAULT '-',
  `TwitterText` varchar(128) DEFAULT '-'
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


-- Table: user_sessions
DROP TABLE IF EXISTS `user_sessions`;
CREATE TABLE `user_sessions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(24) NOT NULL,
  `session_token` varchar(64) NOT NULL,
  `last_chat_time` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `session_token` (`session_token`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: users
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `phone` varchar(20) NOT NULL,
  `name` varchar(50) NOT NULL,
  `coin` bigint(20) NOT NULL DEFAULT 100,
  `mode` enum('easy','normal','hard','extreme') NOT NULL DEFAULT 'normal',
  `banned` tinyint(1) NOT NULL DEFAULT 0,
  `ban_reason` varchar(255) NOT NULL DEFAULT '',
  `total_main` int(11) NOT NULL DEFAULT 0,
  `total_menang` int(11) NOT NULL DEFAULT 0,
  `total_kalah` int(11) NOT NULL DEFAULT 0,
  `total_win` bigint(20) NOT NULL DEFAULT 0,
  `total_lose` bigint(20) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`phone`),
  UNIQUE KEY `uq_name` (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vehicle_components
DROP TABLE IF EXISTS `vehicle_components`;
CREATE TABLE `vehicle_components` (
  `componentid` smallint(4) unsigned NOT NULL,
  `part` enum('Exhausts','Front Bullbars','Front Bumper','Hood','Hydraulics','Lights','Misc','Rear Bullbars','Rear Bumper','Roof','Side Skirts','Spoilers','Vents','Wheels') DEFAULT NULL,
  `type` varchar(22) NOT NULL,
  `cars` smallint(3) NOT NULL,
  PRIMARY KEY (`componentid`),
  KEY `cars` (`cars`),
  KEY `part` (`part`),
  KEY `type` (`type`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


-- Table: vehicle_model_parts
DROP TABLE IF EXISTS `vehicle_model_parts`;
CREATE TABLE `vehicle_model_parts` (
  `modelid` smallint(3) unsigned NOT NULL,
  `parts` bit(9) NOT NULL,
  PRIMARY KEY (`modelid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


-- Table: vouchers
DROP TABLE IF EXISTS `vouchers`;
CREATE TABLE `vouchers` (
  `id` int(11) NOT NULL,
  `code` int(11) NOT NULL DEFAULT 0,
  `vip` int(11) NOT NULL DEFAULT 0,
  `vip_time` int(11) NOT NULL DEFAULT 0,
  `gold` int(11) NOT NULL DEFAULT 0,
  `admin` varchar(16) NOT NULL DEFAULT 'None',
  `donature` varchar(16) NOT NULL DEFAULT 'None',
  `claim` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

-- Table: warn_link
DROP TABLE IF EXISTS `warn_link`;
CREATE TABLE `warn_link` (
  `jid` varchar(100) NOT NULL,
  `sender` varchar(50) NOT NULL,
  `count` int(11) NOT NULL DEFAULT 0,
  PRIMARY KEY (`jid`,`sender`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: warninfo
DROP TABLE IF EXISTS `warninfo`;
CREATE TABLE `warninfo` (
  `wID` int(11) NOT NULL AUTO_INCREMENT,
  `plID` int(11) NOT NULL,
  `wReasonWarn` varchar(64) CHARACTER SET cp1251 COLLATE cp1251_general_ci NOT NULL,
  `wAdminWarn` varchar(64) CHARACTER SET cp1251 COLLATE cp1251_general_ci NOT NULL,
  `wWarnDate` varchar(64) CHARACTER SET cp1251 COLLATE cp1251_general_ci NOT NULL,
  `wUnWarnDate` varchar(64) CHARACTER SET cp1251 COLLATE cp1251_general_ci NOT NULL,
  PRIMARY KEY (`wID`)
) ENGINE=InnoDB AUTO_INCREMENT=253 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;


-- Table: weaponsettings
DROP TABLE IF EXISTS `weaponsettings`;
CREATE TABLE `weaponsettings` (
  `Owner` int(11) NOT NULL DEFAULT 0,
  `WeaponID` int(11) NOT NULL DEFAULT 0,
  `PosX` float(10,3) NOT NULL DEFAULT 0.000,
  `PosY` float(10,3) NOT NULL DEFAULT 0.000,
  `PosZ` float(10,3) NOT NULL DEFAULT 0.000,
  `RotX` float(10,3) NOT NULL DEFAULT 0.000,
  `RotY` float(10,3) NOT NULL DEFAULT 0.000,
  `RotZ` float(10,3) NOT NULL DEFAULT 0.000,
  `Bone` int(11) NOT NULL DEFAULT 0,
  `Hidden` int(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`Owner`,`WeaponID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: whitelist_player
DROP TABLE IF EXISTS `whitelist_player`;
CREATE TABLE `whitelist_player` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `Name` varchar(24) NOT NULL,
  `phone` varchar(20) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_name` (`Name`)
) ENGINE=InnoDB AUTO_INCREMENT=236 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: wishlist
DROP TABLE IF EXISTS `wishlist`;
CREATE TABLE `wishlist` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(24) NOT NULL,
  `item_id` int(11) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_wish` (`username`,`item_id`),
  KEY `idx_username` (`username`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: workshop
DROP TABLE IF EXISTS `workshop`;
CREATE TABLE `workshop` (
  `id` int(11) NOT NULL,
  `owner` varchar(25) NOT NULL DEFAULT '-',
  `posx` float NOT NULL DEFAULT 0,
  `posy` float NOT NULL DEFAULT 0,
  `posz` float NOT NULL DEFAULT 0,
  `component` int(11) NOT NULL DEFAULT 0,
  `money` int(11) NOT NULL DEFAULT 0,
  `material` int(11) NOT NULL DEFAULT 0,
  `name` varchar(26) NOT NULL DEFAULT '-',
  `status` int(11) NOT NULL DEFAULT 0,
  `price` int(11) NOT NULL DEFAULT 0,
  `employe0` varchar(25) NOT NULL DEFAULT '-',
  `employe1` varchar(25) NOT NULL DEFAULT '-',
  `employe2` varchar(25) NOT NULL DEFAULT '-',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;


SET FOREIGN_KEY_CHECKS=1;
